fun solve(nums: Array<Long>, target: Long): Long {
    val N = nums.size
    if (N == 0) {
        return if (target == 0L) 0L else -1L
    }

    val N1 = N / 2
    val N2 = N - N1

    // MapA: XOR Sum -> Maximum Size for the first half
    // Since we are maximizing size, we only store the largest size found for a given XOR sum.
    val mapA = mutableMapOf<Long, Int>()

    // Initialize with the empty set contribution
    mapA[0L] = 0

    // Step 1: Process the first half (A)
    for (i in 1 until (1 shl N1)) {
        var xorSumA = 0L
        var sizeA = 0
        for (j in 0 until N1) {
            if ((i shr j) and 1 == 1) {
                xorSumA = xorSumA xor nums[j]
                sizeA++
            }
        }

        mapA[xorSumA] = maxOf(mapA.getOrDefault(xorSumA, -1), sizeA)
    }

    // Step 2 & 3: Process the second half (B) and combine
    var maxK = -1 // Maximum size of the subset found so far

    // Check the case where only the first half is used (covered by the loop below if we initialize maxK correctly, but let's ensure single-half cases are handled)
    for ((xorA, sizeA) in mapA) {
        if (xorA == target) {
            maxK = maxOf(maxK, sizeA)
        }
    }

    for (i in 0 until (1 shl N2)) {
        var xorSumB = 0L
        var sizeB = 0
        for (j in 0 until N2) {
            if ((i shr j) and 1 == 1) {
                xorSumB = xorSumB xor nums[N1 + j]
                sizeB++
            }
        }

        // Required XOR sum from A: target ^ xorSumB
        val requiredXorA = target xor xorSumB

        if (mapA.containsKey(requiredXorA)) {
            val sizeA = mapA[requiredXorA]!!
            val currentK = sizeA + sizeB
            maxK = maxOf(maxK, currentK)
        }
    }

    if (maxK < 0) {
        return -1L
    }

    // Minimum removal count = Total elements - Maximum kept elements
    return (N - maxK).toLong()
